<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/app_models.php';
require_once __DIR__ . '/../includes/csrf.php';
csrf_start();
if (!empty($_SESSION['master'])) { header('Location: index.php'); exit; }
$error='';
if ($_SERVER['REQUEST_METHOD']==='POST') {
  if (!csrf_verify($_POST['csrf'] ?? '')) $error='Обновите страницу и повторите вход.';
  else {
    $login=trim((string)($_POST['login'] ?? '')); $password=(string)($_POST['password'] ?? '');
    $stmt=db()->prepare('SELECT * FROM masters WHERE login=:login AND is_active=1 LIMIT 1'); $stmt->execute([':login'=>$login]); $master=$stmt->fetch();
    if ($master && password_verify($password, (string)$master['password_hash'])) { $_SESSION['master']=['id'=>(int)$master['id'],'login'=>$master['login'],'name'=>$master['name']]; header('Location: index.php'); exit; }
    else $error='Неверный логин или пароль мастера.';
  }
}
